// --- types.d.ts ---
import { ReactNode } from 'react';

export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastItem[];
}

export interface ForecastDayProps {
  item: ForecastItem;
  unit: string;
}

export interface HookReturn {
  displayTemp: string;
  displayWind: string;
  displayHumidity: string;
  conditionIcon: string;
  weatherTheme: {
    color: string;
    variant: 'elevated' | 'flat' | 'outline';
  };
}


// --- constants.ts ---
import { HookReturn } from './types';

export const DEFAULT_UNIT = 'C';

export const WEATHER_ICONS: Record<string, string> = {
  'Clear': '☀️',
  'Sunny': '☀️',
  'Partly Cloudy': '⛅',
  'Cloudy': '☁️',
  'Overcast': '☁️',
  'Rain': '🌧️',
  'Showers': '🌦️',
  'Drizzle': '🌧️',
  'Thunderstorm': '⛈️',
  'Storm': '🌩️',
  'Snow': '❄️',
  'Fog': '🌫️',
  'Mist': '🌫️',
};

export const WEATHER_THEMES: Record<string, HookReturn['weatherTheme']> = {
  'Clear': { color: 'orange', variant: 'elevated' },
  'Sunny': { color: 'orange', variant: 'elevated' },
  'Partly Cloudy': { color: 'blue', variant: 'flat' },
  'Cloudy': { color: 'grey', variant: 'flat' },
  'Overcast': { color: 'grey', variant: 'flat' },
  'Rain': { color: 'blue', variant: 'outline' },
  'Showers': { color: 'blue', variant: 'outline' },
  'Drizzle': { color: 'blue', variant: 'outline' },
  'Thunderstorm': { color: 'purple', variant: 'elevated' },
  'Storm': { color: 'purple', variant: 'elevated' },
  'Snow': { color: 'blue', variant: 'flat' },
  'Fog': { color: 'grey', variant: 'outline' },
  'Mist': { color: 'grey', variant: 'outline' },
};

export const DEFAULT_THEME: HookReturn['weatherTheme'] = {
  color: 'grey',
  variant: 'flat',
};

export const DEFAULT_ICON = '🌡️';


// --- hooks.ts ---
import { useMemo } from 'react';
import type { Props, HookReturn } from './types';

export function useComponent(props: Props): HookReturn {
  const { temperature, condition, humidity, windSpeed, unit = 'C' } = props;

  const displayTemp = `${temperature}°${unit}`;
  const displayWind = `${windSpeed} km/h`;
  const displayHumidity = `${humidity}%`;

  const weatherTheme = useMemo(() => {
    const cond = condition.toLowerCase();
    if (cond.includes('sun') || cond.includes('clear')) {
      return { color: 'amber', variant: 'elevated' as const };
    }
    if (cond.includes('cloud')) {
      return { color: 'gray', variant: 'flat' as const };
    }
    if (cond.includes('rain') || cond.includes('shower')) {
      return { color: 'blue', variant: 'outline' as const };
    }
    if (cond.includes('storm') || cond.includes('thunder')) {
      return { color: 'indigo', variant: 'elevated' as const };
    }
    if (cond.includes('snow')) {
      return { color: 'sky', variant: 'flat' as const };
    }
    return { color: 'gray', variant: 'flat' as const };
  }, [condition]);

  const conditionIcon = useMemo(() => {
    const cond = condition.toLowerCase();
    if (cond.includes('sun') || cond.includes('clear')) return 'wb_sunny';
    if (cond.includes('cloud')) return 'cloud';
    if (cond.includes('rain') || cond.includes('shower')) return 'water_drop';
    if (cond.includes('storm') || cond.includes('thunder')) return 'thunderstorm';
    if (cond.includes('snow')) return 'ac_unit';
    if (cond.includes('wind')) return 'air';
    return 'wb_cloudy';
  }, [condition]);

  return {
    displayTemp,
    displayWind,
    displayHumidity,
    conditionIcon,
    weatherTheme,
  };
}


