import React from 'react';
import { Box, Stack, Text } from '@ggui-ai/design/primitives';
import type { ForecastDayProps } from './types';

/**
 * ForecastDay Component
 * Displays abbreviated day, icon, and high/low temperatures for a single day.
 */
export function ForecastDay({ item, unit }: ForecastDayProps) {
  const { day, icon, high, low } = item;

  return (
    <Box padding={8}>
      <Stack 
        align="center" 
        gap={4}
      >
        {/* Day Name (Abbreviated) */}
        <Text 
          variant="label" 
          weight="semibold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {day.substring(0, 3)}
        </Text>

        {/* Weather Icon (Emoji) */}
        <Text size="2xl">
          {icon}
        </Text>

        {/* Temperature Range */}
        <Stack direction="horizontal" gap={4} align="center">
          <Text 
            variant="bodySmall" 
            weight="medium"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {Math.round(high)}{unit}
          </Text>
          <Text 
            variant="caption" 
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {Math.round(low)}{unit}
          </Text>
        </Stack>
      </Stack>
    </Box>
  );
}


