// ui.tsx — main visual layout, design system primitives
import React from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Card,
  Divider,
  Icon,
  Box
} from '@ggui-ai/design/primitives';
import type { Props, HookReturn, ForecastDayProps } from './types';

/**
 * ForecastDay component renders an individual day's forecast.
 */
function ForecastDay({ item, unit }: ForecastDayProps) {
  return (
    <Stack gap={4} align="center">
      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        {item.day}
      </Text>
      <Box padding={8}>
        <Icon size={24} color="var(--ggui-color-primary-500, #0ea5e9)">
          <svg
            width="24"
            height="24"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
          >
            <circle cx="12" cy="12" r="5" />
            <path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42" />
          </svg>
        </Icon>
      </Box>
      <Stack direction="horizontal" gap={4}>
        <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          {item.high}{unit}
        </Text>
        <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {item.low}{unit}
        </Text>
      </Stack>
    </Stack>
  );
}

export function ComponentUI(props: Props & HookReturn) {
  const {
    city,
    condition,
    unit = '°C',
    forecast,
    displayTemp,
    displayWind,
    displayHumidity,
    weatherTheme,
  } = props;

  // Map weatherTheme variant to Card props
  const cardProps = {
    shadow: weatherTheme.variant === 'elevated' ? ('md' as const) : ('none' as const),
    border: weatherTheme.variant !== 'flat',
  };

  return (
    <Container maxWidth="md" padding={16}>
      <Card
        padding={24}
        radius="xl"
        {...cardProps}
      >
        <Stack gap={24}>
          {/* Header: City name (Heading) and date/condition */}
          <Stack gap={4}>
            <Heading level={2} color={weatherTheme.color}>
              {city}
            </Heading>
            <Text
              variant="bodySmall"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>

          {/* Main Body: A horizontal Stack with the large temperature and a vertical Stack for Humidity/Wind */}
          <Stack direction="horizontal" justify="between" align="center">
            <Box>
              <Text
                size="4xl"
                weight="bold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {displayTemp}
              </Text>
            </Box>

            <Stack gap={12}>
              <Stack direction="horizontal" gap={8} align="center">
                <Icon size={18} color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  <svg
                    width="18"
                    height="18"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  >
                    <path d="M12 2.69l5.66 5.66a8 8 0 1 1-11.31 0z" />
                  </svg>
                </Icon>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  {displayHumidity}
                </Text>
              </Stack>
              <Stack direction="horizontal" gap={8} align="center">
                <Icon size={18} color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  <svg
                    width="18"
                    height="18"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  >
                    <path d="M17.7 7.7a2.5 2.5 0 1 1 1.8 4.3H2" />
                    <path d="M9.6 4.6A2 2 0 1 1 11 8H2" />
                    <path d="M12.6 19.4A2 2 0 1 0 14 16H2" />
                  </svg>
                </Icon>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  {displayWind}
                </Text>
              </Stack>
            </Stack>
          </Stack>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          {/* Footer: A horizontal Stack or Grid containing the ForecastDay components */}
          <Stack
            direction="horizontal"
            justify="between"
            gap={16}
            wrap
          >
            {forecast.map((item, index) => (
              <ForecastDay
                key={`${item.day}-${index}`}
                item={item}
                unit={unit}
              />
            ))}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}


